import type { SyntaxNodeRef } from '@lezer/common';

import type { ConvertedLezerNode } from '../../../../types/conversion-utils.js';
import type { FilterFieldExistsOperatorNode } from '../../../../types/tree-nodes.js';
import { getTextFromRange } from '../../../get-text.js';

/**
 * Convert an exists operator node.
 * @internal
 */
export function convertExistsOperator(
  node: SyntaxNodeRef,
  doc: string,
): ConvertedLezerNode<FilterFieldExistsOperatorNode> {
  const { from, to } = node;
  const textValue = getTextFromRange(node, doc);

  const convertedNode: FilterFieldExistsOperatorNode = {
    type: 'ExistsOperator',
    range: {
      from,
      to,
    },
    textValue,
    value: textValue === '= *' || textValue === '=*',
  };

  return {
    convertedNode,
    errors: [],
  };
}
